# Configuration
WIFI_SSID = "YOUR_WIFI_SSID"
WIFI_PASSWORD = "YOUR_WIFI_PASSWORD"
WS_PORT = 8080

# Device state
device_state = {
    "led": False,
    "relay": False,
    "brightness": 0,
    "temperature": 0.0,
    "status": "idle"
}

# Pin setup
led_pin = machine.Pin(2, machine.Pin.OUT)  # Built-in LED on most ESP32
relay_pin = machine.Pin(4, machine.Pin.OUT)
pwm_pin = machine.PWM(machine.Pin(5), freq=1000, duty=0)

# Connected WebSocket clients
clients = []
clients_lock = _thread.allocate_lock()


def connect_wifi():
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    if not wlan.isconnected():
        print("Connecting to WiFi...")
        wlan.connect(WIFI_SSID, WIFI_PASSWORD)
        timeout = 20
        while not wlan.isconnected() and timeout > 0:
            time.sleep(1)
            timeout -= 1
            print(".", end="")
    if wlan.isconnected():
        ip = wlan.ifconfig()[0]
        print("\nConnected! IP:", ip)
        return ip
    else:
        print("\nFailed to connect to WiFi")
        return None


def sha1(data):
    return hashlib.sha1(data).digest()


def base64_encode(data):
    return binascii.b2a_base64(data).strip()


def parse_http_headers(data):
    headers = {}
    lines = data.decode("utf-8").split("\r\n")
    request_line = lines[0] if lines else ""
    for line in lines[1:]:
        if ":" in line:
            key, value = line.split(":", 1)
            headers[key.strip().lower()] = value.strip()
    return request_line, headers


def websocket_handshake(client_socket, headers):
    WS_MAGIC = b"258EAFA5-E914-47DA-95CA-5AB9CFDCE85B"
    key = headers.get("sec-websocket-key", "")
    if not key:
        return False
    accept_key = base64_encode(sha1(key.encode("utf-8") + WS_MAGIC))
    response = (
        "HTTP/1.1 101 Switching Protocols\r\n"
        "Upgrade: websocket\r\n"
        "Connection: Upgrade\r\n"
        "Sec-WebSocket-Accept: " + accept_key.decode("utf-8") + "\r\n"
        "\r\n"
    )
    client_socket.send(response.encode("utf-8"))
    return True


def ws_decode_frame(data):
    if len(data) < 2:
        return None, None, 0

    opcode = data[0] & 0x0F
    masked = (data[1] & 0x80) != 0
    payload_len = data[1] & 0x7F
    offset = 2

    if payload_len == 126:
        if len(data) < 4:
            return None, None, 0
        payload_len = struct.unpack(">H", data[2:4])[0]
        offset = 4
    elif payload_len == 127:
        if len(data) < 10:
            return None, None, 0
        payload_len = struct.unpack(">Q", data[2:10])[0]
        offset = 10

    if masked:
        if len(data) < offset + 4 + payload_len:
            return None, None, 0
        mask = data[offset:offset + 4]
        offset += 4
        payload = bytearray(data[offset:offset + payload_len])
        for i in range(payload_len):
            payload[i] ^= mask[i % 4]
        payload = bytes(payload)
    else:
        if len(data) < offset + payload_len:
            return None, None, 0
        payload = data[offset:offset + payload_len]

    total_consumed = offset + payload_len
    return opcode, payload, total_consumed


def ws_encode_frame(data, opcode=0x01):
    frame = bytearray()
    frame.append(0x80 | opcode)  # FIN + opcode

    if isinstance(data, str):
        data = data.encode("utf-8")

    length = len(data)
    if length < 126:
        frame.append(length)
    elif length < 65536:
        frame.append(126)
        frame.extend(struct.pack(">H", length))
    else:
        frame.append(127)
        frame.extend(struct.pack(">Q", length))

    frame.extend(data)
    return bytes(frame)


def broadcast_state():
    message = json.dumps({
        "type": "state_update",
        "state": device_state,
        "timestamp": time.time()
    })
    frame = ws_encode_frame(message)
    clients_lock.acquire()
    disconnected = []
    for client in clients:
        try:
            client.send(frame)
        except Exception:
            disconnected.append(client)
    for client in disconnected:
        clients.remove(client)
        try:
            client.close()
        except Exception:
            pass
    clients_lock.release()


def send_response(client_socket, response_data):
    message = json.dumps(response_data)
    frame = ws_encode_frame(message)
    try:
        client_socket.send(frame)
    except Exception:
        pass


def handle_command(client_socket, command):
    action = command.get("action", "")
    target = command.get("target", "led")
    value = command.get("value", None)

    response = {
        "type": "response",
        "action": action,
        "success": True,
        "message": ""
    }

    try:
        if action == "turn_on":
            if target == "led":
                led_pin.value(1)
                device_state["led"] = True
                response["message"] = "LED turned on"
            elif target == "relay":
                relay_pin.value(1)
                device_state["relay"] = True
                response["message"] = "Relay turned on"
            else:
                response["success"] = False
                response["message"] = f"Unknown target: {target}"

        elif action == "turn_off":
            if target == "led":
                led_pin.value(0)
                device_state["led"] = False
                response["message"] = "LED turned off"
            elif target == "relay":
                relay_pin.value(0)
                device_state["relay"] = False
                response["message"] = "Relay turned off"
            else:
                response["success"] = False
                response["message"] = f"Unknown target: {target}"

        elif action == "toggle":
            if target == "led":
                new_val = not device_state["led"]
                led_pin.value(1 if new_val else 0)
                device_state["led"] = new_val
                response["message"] = f"LED {'on' if new_val else 'off'}"
            elif target == "relay":
                new_val = not device_state["relay"]
                relay_pin.value(1 if new_val else 0)
                device_state["relay"] = new_val
                response["message"] = f"Relay {'on' if new_val else 'off'}"

        elif action == "set_brightness":
            if value is not None:
                brightness = max(0, min(100, int(value)))
                duty = int(brightness * 1023 / 100)
                pwm_pin.duty(duty)
                device_state["brightness"] = brightness
                response["message"] = f"Brightness set to {brightness}%"
            else:
                response["success"] = False
                response["message"] = "Value required for set_brightness"

        elif action == "get_state":
            response["message"] = "Current state"
            response["state"] = device_state

        elif action == "ping":
            response["message"] = "pong"
            response["type"] = "pong"

        elif action == "restart":
            response["message"] = "Restarting device..."
            send_response(client_socket, response)
            time.sleep(1)
            machine.reset()

        elif action == "set_status":
            if value is not None:
                device_state["status"] = str(value)
                response["message"] = f"Status set to: {value}"
            else:
                response["success"] = False
                response["message"] = "Value required for set_status"

        else:
            response["success"] = False
            response["message"] = f"Unknown action: {action}"

    except Exception as e:
        response["success"] = False
        response["message"] = f"Error: {str(e)}"

    send_response(client_socket, response)

    if response["success"] and action != "get_state" and action != "ping":
        broadcast_state()


def handle_client(client_socket, client_addr):
    print(f"New connection from {client_addr}")

    try:
        # Receive HTTP upgrade request
        data = client_socket.recv(1024)
        if not data:
            client_socket.close()
            return

        request_line, headers = parse_http_headers(data)

        # Check if this is a WebSocket upgrade request
        upgrade = headers.get("upgrade", "").lower()

        if upgrade == "websocket":
            if not websocket_handshake(client_socket, headers):
                print("WebSocket handshake failed")
                client_socket.close()
                return

            print(f"WebSocket connected: {client_addr}")

            clients_lock.acquire()
            clients.append(client_socket)
            clients_lock.release()

            # Send initial state
            welcome = json.dumps({
                "type": "welcome",
                "message": "Connected to ESP32 IoT Controller",
                "state": device_state,
                "available_actions": [
                    "turn_on", "turn_off", "toggle",
                    "set_brightness", "get_state", "ping",
                    "restart", "set_status"
                ],
                "available_targets": ["led", "relay"]
            })
            client_socket.send(ws_encode_frame(welcome))

            # Message loop
            buffer = b""
            client_socket.settimeout(0.5)

            while True:
                try:
                    chunk = client_socket.recv(1024)
                    if not chunk:
                        break
                    buffer += chunk
                except OSError:
                    # Timeout - just continue
                    continue

                while buffer:
                    opcode, payload, consumed = ws_decode_frame(buffer)

                    if opcode is None:
                        break

                    buffer = buffer[consumed:]

                    if opcode == 0x08:  # Close frame
                        print(f"Client {client_addr} sent close frame")
                        close_frame = ws_encode_frame(b"", opcode=0x08)
                        try:
                            client_socket.send(close_frame)
                        except Exception:
                            pass
                        raise StopIteration()

                    elif opcode == 0x09:  # Ping
                        pong_frame = ws_encode_frame(payload, opcode=0x0A)
                        client_socket.send(pong_frame)

                    elif opcode == 0x0A:  # Pong
                        pass

                    elif opcode in (0x01, 0x02):  # Text or Binary
                        try:
                            message = payload.decode("utf-8")
                            print(f"Received from {client_addr}: {message}")
                            command = json.loads(message)
                            handle_command(client_socket, command)
                        except json.JSONDecodeError:
                            error_resp = json.dumps({
                                "type": "error",
                                "message": "Invalid JSON format. Expected: {\"action\": \"turn_on\", \"target\": \"led\"}"
                            })
                            client_socket.send(ws_encode_frame(error_resp))
                        except Exception as e:
                            error_resp = json.dumps({
                                "type": "error",
                                "message": str(e)
                            })
                            client_socket.send(ws_encode_frame(error_resp))

        else:
            # Serve the web interface
            html_response = generate_html()
            response = (
                "HTTP/1.1 200 OK\r\n"
                "Content-Type: text/html\r\n"
                "Content-Length: " + str(len(html_response)) + "\r\n"
                "Connection: close\r\n"
                "\r\n"
            )
            client_socket.send(response.encode("utf-8"))
            client_socket.send(html_response.encode("utf-8"))
            client_socket.close()
            return

    except StopIteration:
        pass
    except Exception as e:
        print(f"Client error ({client_addr}): {e}")
    finally:
        clients_lock.acquire()
        if client_socket in clients:
            clients.remove(client_socket)
        clients_lock.release()
        try:
            client_socket.close()
        except Exception:
            pass
        print(f"Client disconnected: {client_addr}")


