def start_server(ip):
    server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
    server_socket.bind(("0.0.0.0", WS_PORT))
    server_socket.listen(5)
    print(f"WebSocket server running at ws://{ip}:{WS_PORT}/")
    print(f"Web interface at http://{ip}:{WS_PORT}/")

    while True:
        try:
            client_socket, client_addr = server_socket.accept()
            _thread.start_new_thread(handle_client, (client_socket, client_addr))
        except Exception as e:
            print(f"Server accept error: {e}")
            time.sleep(1)


def main():
    # Initialize pins to off
    led_pin.value(0)
    relay_pin.value(0)
    pwm_pin.duty(0)

    ip = connect_wifi()
    if ip:
        start_server(ip)
    else:
        print("Cannot start server without WiFi connection")
        # Blink LED to indicate error
        for _ in range(10):
            led_pin.value(1)
            time.sleep(0.2)
            led_pin.value(0)
            time.sleep(0.2)
        machine.reset()


if __name__ == "__main__":
    main()